// @kern-source: results-formatter:207
export function formatSessionResults(results: SessionResult[]): string {
  if (results.length === 0) {
    return `${DIM}No results in this session yet. Run /brainstorm, /campfire, /tribunal, /forge, /think, /council, /synthesis, or /nero first.${RESET}\n`;
  }

  const sections: string[] = [];
  sections.push(`${BOLD}Session Results (${results.length})${RESET}\n`);

  for (let i = 0; i < results.length; i++) {
    const r = results[i];
    const idx = i + 1;
    switch (r.type) {
      case 'brainstorm': sections.push(formatBrainstorm(r, idx)); break;
      case 'campfire': sections.push(formatCampfire(r, idx)); break;
      case 'tribunal': sections.push(formatTribunal(r, idx)); break;
      case 'forge': sections.push(formatForge(r, idx)); break;
      case 'think': sections.push(formatThink(r, idx)); break;
      case 'council': sections.push(formatCouncil(r, idx)); break;
      case 'synthesis': sections.push(formatSynthesis(r, idx)); break;
      case 'nero': sections.push(formatNero(r, idx)); break;
    }
  }

  return sections.join('\n');
}
